                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       <div className="pointer-events-none absolute inset-0" style={{ background: `radial-gradient(circle at 80% 20%, ${tint.overlay}, transparent 35%)` }} />
