                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     <div className="absolute inset-0 opacity-55" style={{ background: `radial-gradient(circle at 50% 40%, ${tint.overlay}, transparent 60%)` }} />
